#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMdbxVault: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = MdbxVault

    public static func lift(_ handle: UInt64) throws -> MdbxVault {
        return MdbxVault(unsafeFromHandle: handle)
    }

    public static func lower(_ value: MdbxVault) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> MdbxVault {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: MdbxVault, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMdbxVault_lift(_ handle: UInt64) throws -> MdbxVault {
    return try FfiConverterTypeMdbxVault.lift(handle)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMdbxVault_lower(_ value: MdbxVault) -> UInt64 {
    return FfiConverterTypeMdbxVault.lower(value)
}




public struct CardEntryRecord: Equatable, Hashable {
    public var entryId: String
    public var projectId: String
    public var title: String
    public var cardholderName: String
    public var number: String
    public var expiryMonth: String
    public var expiryYear: String
    public var cvv: String
    public var issuer: String
    public var network: String
    public var notes: String
    public var favorite: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(entryId: String, projectId: String, title: String, cardholderName: String, number: String, expiryMonth: String, expiryYear: String, cvv: String, issuer: String, network: String, notes: String, favorite: Bool) {
        self.entryId = entryId
        self.projectId = projectId
        self.title = title
        self.cardholderName = cardholderName
        self.number = number
        self.expiryMonth = expiryMonth
        self.expiryYear = expiryYear
        self.cvv = cvv
        self.issuer = issuer
        self.network = network
        self.notes = notes
        self.favorite = favorite
    }

    

    
}

